#!/usr/bin/env sh
set -eu

root_dir=$(CDPATH= cd -- "$(dirname -- "$0")/.." && pwd)
cd "$root_dir"

echo "== Build gate =="
lake build

echo "== Interface gate =="
sh scripts/interface_audit.sh

echo "== Mathlib gap gate =="
sh scripts/mathlib_gap_audit.sh

echo "== Semantic surface gate =="
sh scripts/semantic_surface_audit.sh

echo "== Root import gate =="
sh scripts/root_import_audit.sh

echo "== Axiom footprint gate =="
sh scripts/axiom_audit.sh

echo "== Shape contract gate =="
sh scripts/shape_contract_audit.sh

echo "== Theorem contract gate =="
sh scripts/theorem_contract_audit.sh

echo "== Objective =="
cat <<'TEXT'
Implement a complete Lean proof of the Poincare Conjecture:
every closed, simply connected topological 3-manifold is homeomorphic to S^3.
TEXT

echo "== Prompt-to-artifact checklist =="

status=0
completion_check=
completion_check_dir=
dependency_contract_check=
dependency_contract_check_dir=
root_contract_check=
root_contract_check_dir=
route_parity_dir=
constructor_surface_dir=

cleanup() {
  if [ -n "$constructor_surface_dir" ]; then
    rm -rf "$constructor_surface_dir"
  fi
  if [ -n "$route_parity_dir" ]; then
    rm -rf "$route_parity_dir"
  fi
  if [ -n "$root_contract_check_dir" ]; then
    rm -rf "$root_contract_check_dir"
  fi
  if [ -n "$root_contract_check" ]; then
    rm -f "$root_contract_check"
  fi
  if [ -n "$dependency_contract_check_dir" ]; then
    rm -rf "$dependency_contract_check_dir"
  fi
  if [ -n "$dependency_contract_check" ]; then
    rm -f "$dependency_contract_check"
  fi
  if [ -n "$completion_check_dir" ]; then
    rm -rf "$completion_check_dir"
  fi
  if [ -n "$completion_check" ]; then
    rm -f "$completion_check"
  fi
}

trap cleanup EXIT

check_present() {
  label=$1
  path=$2
  if [ -e "$path" ]; then
    echo "PASS: $label -> $path exists"
  else
    echo "FAIL: $label -> $path missing"
    status=1
  fi
}

check_present "Lean project manifest" "lakefile.lean"
check_present "Lean toolchain pin" "lean-toolchain"
check_present "Root Lean module" "Poincare.lean"
check_present "Poincare statement layer" "Poincare/Statement.lean"
check_present "Poincare assembly lemmas" "Poincare/Assembly.lean"
check_present "Canonical completion bridges" "Poincare/CanonicalBridges.lean"
check_present "Minimal Ricci-flow API" "Poincare/RicciFlow.lean"
check_present "Analytic Ricci-flow foundation interface" "Poincare/AnalyticFoundation.lean"
check_present "Ricci-flow-with-surgery interface" "Poincare/Surgery.lean"
check_present "Ricci-flow interface layer" "Poincare/RicciFlowInterface.lean"
check_present "Topology extraction interface" "Poincare/TopologyExtraction.lean"
check_present "Smoothability interface" "Poincare/Smoothability.lean"
check_present "End-to-end conditional assembly" "Poincare/FullAssembly.lean"
check_present "Aggregate dependency package" "Poincare/Dependencies.lean"
check_present "Dependency projection lemmas" "Poincare/DependencyProjections.lean"
check_present "Dependency crosswalk" "Poincare/DependencyCrosswalk.lean"
check_present "Canonical completion target" "Poincare/CompletionTarget.lean"
check_present "Lean dependency milestone ledger" "Poincare/Milestones.lean"
check_present "Markdown dependency ledger" "DEPENDENCY_LEDGER.md"
check_present "Mathlib gap analysis" "MATHLIB_GAP_ANALYSIS.md"
check_present "External research status" "EXTERNAL_RESEARCH_STATUS.md"
check_present "Progress report" "POINCARE_FORMALIZATION_REPORT.md"
check_present "Generated current status" "CURRENT_STATUS.md"
check_present "Shape contract audit" "scripts/shape_contract_audit.sh"

if rg -q '^- Completion: not achieved$' CURRENT_STATUS.md &&
    rg -q '^- Axiom footprint audit status: 0$' CURRENT_STATUS.md &&
    rg -q '^- Shape contract audit status: 0$' CURRENT_STATUS.md &&
    rg -q '^- Completion audit status: 1$' CURRENT_STATUS.md; then
  echo "PASS: generated status snapshot records clean axiom/shape audits and incomplete completion audit"
else
  echo "FAIL: generated status snapshot does not record the current axiom/shape/completion state"
  status=1
fi

toolchain=$(tr -d '\n' < lean-toolchain)
if rg -q "^- Lean toolchain: ${toolchain}$" CURRENT_STATUS.md; then
  echo "PASS: generated status snapshot matches current Lean toolchain"
else
  echo "FAIL: generated status snapshot does not match current Lean toolchain"
  status=1
fi

if rg -q '^def PoincareConjectureStatement\b' Poincare/Statement.lean; then
  echo "PASS: target proposition is stated in Poincare/Statement.lean"
else
  echo "FAIL: target proposition is not stated"
  status=1
fi

if rg -q 'SimplyConnectedSpace.nonempty_homeomorph_sphere_three|SimplyConnectedSpace.nonempty_diffeomorph_sphere_three' \
    .lake/packages/mathlib/Mathlib/Geometry/Manifold/PoincareConjecture.lean; then
  echo "PASS: canonical mathlib Poincare statement file is present"
else
  echo "FAIL: canonical mathlib Poincare statement file not found"
  status=1
fi

if rg -q '^proof_wanted .*nonempty_(homeomorph|diffeomorph)_sphere_three' \
    .lake/packages/mathlib/Mathlib/Geometry/Manifold/PoincareConjecture.lean; then
  echo "GAP: upstream mathlib still marks 3D Poincare statements as proof_wanted"
  rg -n '^proof_wanted .*nonempty_(homeomorph|diffeomorph)_sphere_three' \
    .lake/packages/mathlib/Mathlib/Geometry/Manifold/PoincareConjecture.lean
else
  echo "PASS: upstream mathlib no longer marks 3D Poincare statements as proof_wanted"
fi

check_decl() {
  label=$1
  pattern=$2
  path=$3
  if rg -q "$pattern" "$path"; then
    echo "PASS: $label"
  else
    echo "FAIL: $label"
    status=1
  fi
}

check_payload_route_parity() {
  route_parity_dir=$(mktemp -d)
  awk '/^theorem / {print $2}' \
    Poincare/CompletionTarget.lean Poincare/CanonicalBridges.lean \
    > "$route_parity_dir/theorems"
  sed -n 's/^poincareCompletionCertificate_theoremName_payload_of_completion_certificate_of_\(.*\)_eq$/\1/p' \
    "$route_parity_dir/theorems" | sort -u > "$route_parity_dir/theoremName.routes"
  for family in literal canonical_statement aggregate_canonical_statement aggregate_dependency project_statement; do
    sed -n "s/^poincareCompletionCertificate_${family}_payload_of_completion_certificate_of_\\(.*\\)_eq$/\\1/p" \
      "$route_parity_dir/theorems" | sort -u > "$route_parity_dir/${family}.routes"
    missing_theorem_name=$(comm -13 "$route_parity_dir/theoremName.routes" "$route_parity_dir/${family}.routes")
    missing_family=$(comm -23 "$route_parity_dir/theoremName.routes" "$route_parity_dir/${family}.routes")
    {
      sed -n "s/^completion_certificate_of_${family}_payload_of_\\(.*\\)_eq$/\\1/p" \
        "$route_parity_dir/theorems"
      sed -n "s/^completion_certificate_of_${family}_payload_of_completion_certificate_of_\\(.*\\)_eq$/\\1/p" \
        "$route_parity_dir/theorems"
    } | sort -u > "$route_parity_dir/${family}.constructor.routes"
    missing_constructor=$(comm -23 "$route_parity_dir/${family}.routes" "$route_parity_dir/${family}.constructor.routes")

    if [ -n "$missing_theorem_name" ]; then
      echo "FAIL: $family payload routes without theorem-name payload counterparts"
      printf '%s\n' "$missing_theorem_name"
      status=1
    else
      echo "PASS: $family payload routes have theorem-name payload counterparts"
    fi

    if [ -n "$missing_family" ]; then
      echo "FAIL: theorem-name payload routes without $family payload counterparts"
      printf '%s\n' "$missing_family"
      status=1
    else
      echo "PASS: theorem-name payload routes have $family payload counterparts"
    fi

    if [ -n "$missing_constructor" ]; then
      echo "FAIL: $family payload projection routes without constructor counterparts"
      printf '%s\n' "$missing_constructor"
      status=1
    else
      echo "PASS: $family payload projection routes have constructor counterparts"
    fi
  done
}

check_completion_constructor_endpoint_coverage() {
  constructor_surface_dir=$(mktemp -d)
  constructor_surface_constructors="$constructor_surface_dir/constructors"
  constructor_surface_boundary_constructors="$constructor_surface_dir/boundary-constructors"
  constructor_surface_endpoints="$constructor_surface_dir/endpoints"
  constructor_surface_missing="$constructor_surface_dir/missing"
  constructor_surface_payload_endpoints="$constructor_surface_dir/payload-endpoints"
  constructor_surface_payload_missing="$constructor_surface_dir/payload-missing"
  constructor_surface_target_endpoints="$constructor_surface_dir/target-endpoints"
  constructor_surface_target_missing="$constructor_surface_dir/target-missing"
  constructor_surface_canonical_payload_endpoints="$constructor_surface_dir/canonical-payload-endpoints"
  constructor_surface_canonical_payload_missing="$constructor_surface_dir/canonical-payload-missing"
  constructor_surface_project_payload_endpoints="$constructor_surface_dir/project-payload-endpoints"
  constructor_surface_project_payload_missing="$constructor_surface_dir/project-payload-missing"
  constructor_surface_canonical_target_endpoints="$constructor_surface_dir/canonical-target-endpoints"
  constructor_surface_canonical_target_missing="$constructor_surface_dir/canonical-target-missing"
  constructor_surface_criterion_endpoints="$constructor_surface_dir/criterion-endpoints"
  constructor_surface_criterion_missing="$constructor_surface_dir/criterion-missing"
  constructor_surface_canonical_criterion_endpoints="$constructor_surface_dir/canonical-criterion-endpoints"
  constructor_surface_canonical_criterion_missing="$constructor_surface_dir/canonical-criterion-missing"
  constructor_surface_full_assembly_endpoints="$constructor_surface_dir/full-assembly-endpoints"
  constructor_surface_full_assembly_missing="$constructor_surface_dir/full-assembly-missing"
  constructor_surface_certified_full_assembly_endpoints="$constructor_surface_dir/certified-full-assembly-endpoints"
  constructor_surface_certified_full_assembly_missing="$constructor_surface_dir/certified-full-assembly-missing"
  constructor_surface_payload_route_endpoints="$constructor_surface_dir/payload-route-endpoints"
  constructor_surface_payload_route_missing="$constructor_surface_dir/payload-route-missing"

  perl -0ne 'while (/^theorem\s+(completion_certificate_of_[A-Za-z0-9_]+)\b(.*?)(?=^theorem\s+|\z)/msg) { my ($n,$b)=($1,$2); next if $n =~ /_eq$/; next unless $b =~ /:\s*PoincareCompletionCertificate\.\{u\}/s; print "$n\n"; }' \
    Poincare/CompletionTarget.lean | sort -u > "$constructor_surface_constructors"

  rg --no-filename -o '^theorem poincare_conjecture_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sort -u > "$constructor_surface_endpoints"

  if [ ! -s "$constructor_surface_constructors" ]; then
    echo "FAIL: no completion certificate constructors found for theorem endpoint coverage audit"
    status=1
    return
  fi

  comm -23 "$constructor_surface_constructors" "$constructor_surface_endpoints" \
    > "$constructor_surface_missing"

  if [ -s "$constructor_surface_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a reserved theorem endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a reserved theorem endpoint"
  fi

  rg --no-filename -o '^theorem poincare_conjecture_payload_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_payload_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_payload_endpoints" \
    > "$constructor_surface_payload_missing"

  if [ -s "$constructor_surface_payload_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a reserved payload endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_payload_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a reserved payload endpoint"
  fi

  rg --no-filename -o '^theorem target_statement_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_target_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_target_endpoints" \
    > "$constructor_surface_target_missing"

  if [ -s "$constructor_surface_target_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a target-statement endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_target_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a target-statement endpoint"
  fi

  rg --no-filename -o '^theorem canonical_completion_payload_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_canonical_payload_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_canonical_payload_endpoints" \
    > "$constructor_surface_canonical_payload_missing"

  if [ -s "$constructor_surface_canonical_payload_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a canonical-payload endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_canonical_payload_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a canonical-payload endpoint"
  fi

  rg --no-filename -o '^theorem poincare_completion_payload_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_project_payload_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_project_payload_endpoints" \
    > "$constructor_surface_project_payload_missing"

  if [ -s "$constructor_surface_project_payload_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a project-payload endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_project_payload_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a project-payload endpoint"
  fi

  rg --no-filename -o '^theorem canonical_completion_target_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_canonical_target_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_canonical_target_endpoints" \
    > "$constructor_surface_canonical_target_missing"

  if [ -s "$constructor_surface_canonical_target_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a canonical-target endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_canonical_target_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a canonical-target endpoint"
  fi

  rg --no-filename -o '^theorem completion_criterion_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_criterion_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_criterion_endpoints" \
    > "$constructor_surface_criterion_missing"

  if [ -s "$constructor_surface_criterion_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a completion-criterion endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_criterion_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a completion-criterion endpoint"
  fi

  rg --no-filename -o '^theorem canonical_completion_criterion_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_canonical_criterion_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_canonical_criterion_endpoints" \
    > "$constructor_surface_canonical_criterion_missing"

  if [ -s "$constructor_surface_canonical_criterion_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a canonical-criterion endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_canonical_criterion_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a canonical-criterion endpoint"
  fi

  rg --no-filename -o '^theorem poincare_full_assembly_payload_of_completion_certificate_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_full_assembly_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_full_assembly_endpoints" \
    > "$constructor_surface_full_assembly_missing"

  if [ -s "$constructor_surface_full_assembly_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a full-assembly endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_full_assembly_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a full-assembly endpoint"
  fi

  rg --no-filename -o '^theorem poincare_full_assembly_payload_of_completion_certificate_extraction_derivation_of_([A-Za-z0-9_]+)\b' \
    -r 'completion_certificate_of_$1' \
    Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
    sed '/_eq$/d' |
    sort -u > "$constructor_surface_certified_full_assembly_endpoints"

  comm -23 "$constructor_surface_constructors" "$constructor_surface_certified_full_assembly_endpoints" \
    > "$constructor_surface_certified_full_assembly_missing"

  if [ -s "$constructor_surface_certified_full_assembly_missing" ]; then
    echo "FAIL: every completion certificate constructor exposes a certified full-assembly endpoint"
    sed 's/^/MISSING: /' "$constructor_surface_certified_full_assembly_missing"
    status=1
  else
    echo "PASS: every completion certificate constructor exposes a certified full-assembly endpoint"
  fi

  for payload_route_family in theoremName literal canonical_statement aggregate_canonical_statement aggregate_dependency project_statement; do
    rg --no-filename -o "^theorem poincareCompletionCertificate_${payload_route_family}_payload_of_completion_certificate_of_([A-Za-z0-9_]+)_eq\b" \
      -r 'completion_certificate_of_$1' \
      Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
      sort -u > "$constructor_surface_payload_route_endpoints"

    comm -23 "$constructor_surface_constructors" "$constructor_surface_payload_route_endpoints" \
      > "$constructor_surface_payload_route_missing"

    if [ -s "$constructor_surface_payload_route_missing" ]; then
      echo "FAIL: every completion certificate constructor exposes a ${payload_route_family} payload route"
      sed 's/^/MISSING: /' "$constructor_surface_payload_route_missing"
      status=1
    else
      echo "PASS: every completion certificate constructor exposes a ${payload_route_family} payload route"
    fi
  done

  perl -0ne 'while (/^theorem\s+(completion_certificate_with_equation_boundary_verification_payload_of_[A-Za-z0-9_]+)\b(.*?)(?=^theorem\s+|\z)/msg) { my ($n,$b)=($1,$2); next if $n =~ /_eq$/; next unless $b =~ /:\s*PoincareCompletionCertificateWithEquationBoundaryVerificationPayload\.\{u\}/s; print "$n\n"; }' \
    Poincare/CompletionTarget.lean Poincare/CanonicalBridges.lean |
    sort -u > "$constructor_surface_boundary_constructors"

  if [ ! -s "$constructor_surface_boundary_constructors" ]; then
    echo "FAIL: no boundary-aware completion certificate constructors found for endpoint coverage audit"
    status=1
    return
  fi

  for boundary_endpoint_family in \
      poincare_completion_payload_of_completion_certificate_with_equation_boundary_verification_payload \
      target_statement_of_completion_certificate_with_equation_boundary_verification_payload \
      canonical_completion_target_of_completion_certificate_with_equation_boundary_verification_payload \
      poincare_conjecture_of_completion_certificate_with_equation_boundary_verification_payload \
      poincare_conjecture_payload_of_completion_certificate_with_equation_boundary_verification_payload \
      completion_criterion_of_completion_certificate_with_equation_boundary_verification_payload \
      canonical_completion_criterion_of_completion_certificate_with_equation_boundary_verification_payload \
      poincare_full_assembly_payload_of_completion_certificate_with_equation_boundary_verification_payload \
      poincare_full_assembly_payload_of_completion_certificate_with_equation_boundary_verification_payload_extraction_derivation \
      canonical_three_sphere_statement_of_completion_certificate_with_equation_boundary_verification_payload \
      poincareCompletionCertificate_canonical_statement_payload_of_completion_certificate_with_equation_boundary_verification_payload \
      poincareCompletionCertificate_aggregate_canonical_statement_payload_of_completion_certificate_with_equation_boundary_verification_payload; do
    rg --no-filename -o "^theorem ${boundary_endpoint_family}_of_([A-Za-z0-9_]+)\b" \
      -r 'completion_certificate_with_equation_boundary_verification_payload_of_$1' \
      Poincare/CanonicalBridges.lean Poincare/CompletionTarget.lean |
      sed '/_eq$/d' |
      sort -u > "$constructor_surface_payload_route_endpoints"

    comm -23 "$constructor_surface_boundary_constructors" "$constructor_surface_payload_route_endpoints" \
      > "$constructor_surface_payload_route_missing"

    if [ -s "$constructor_surface_payload_route_missing" ]; then
      echo "FAIL: every boundary-aware completion certificate constructor exposes ${boundary_endpoint_family}"
      sed 's/^/MISSING: /' "$constructor_surface_payload_route_missing"
      status=1
    else
      echo "PASS: every boundary-aware completion certificate constructor exposes ${boundary_endpoint_family}"
    fi
  done
}

check_payload_route_parity
check_completion_constructor_endpoint_coverage

check_decl "Ricci tensor interface is declared" \
  '^inductive IsRicciTensorOf\b' Poincare/RicciFlow.lean
check_decl "target sphere model contract is declared" \
  '^theorem threeSphere_eq\b' Poincare/Statement.lean
check_decl "target sphere Hausdorff theorem is declared" \
  '^theorem threeSphere_t2Space\b' Poincare/Statement.lean
check_decl "target sphere Hausdorff equality contract is declared" \
  '^theorem threeSphere_t2Space_eq\b' Poincare/Statement.lean
check_decl "target sphere compact theorem is declared" \
  '^theorem threeSphere_compactSpace\b' Poincare/Statement.lean
check_decl "target sphere compact equality contract is declared" \
  '^theorem threeSphere_compactSpace_eq\b' Poincare/Statement.lean
check_decl "target sphere charted-space witness is declared" \
  '^@\[reducible\] noncomputable def threeSphere_chartedSpace\b' Poincare/Statement.lean
check_decl "target sphere charted-space equality contract is declared" \
  '^theorem threeSphere_chartedSpace_eq\b' Poincare/Statement.lean
check_decl "target sphere smooth manifold theorem is declared" \
  '^theorem threeSphere_smoothManifold\b' Poincare/Statement.lean
check_decl "target sphere smooth manifold equality contract is declared" \
  '^theorem threeSphere_smoothManifold_eq\b' Poincare/Statement.lean
check_decl "target sphere ambient rank witness is declared" \
  '^theorem threeSphere_euclidean_rank_gt_one\b' Poincare/Statement.lean
check_decl "target sphere ambient rank equality contract is declared" \
  '^theorem threeSphere_euclidean_rank_gt_one_eq\b' Poincare/Statement.lean
check_decl "target sphere path-connected set theorem is declared" \
  '^theorem threeSphere_isPathConnected_set\b' Poincare/Statement.lean
check_decl "target sphere path-connected set equality contract is declared" \
  '^theorem threeSphere_isPathConnected_set_eq\b' Poincare/Statement.lean
check_decl "target sphere path-connected type theorem is declared" \
  '^theorem threeSphere_pathConnectedSpace\b' Poincare/Statement.lean
check_decl "target sphere path-connected type equality contract is declared" \
  '^theorem threeSphere_pathConnectedSpace_eq\b' Poincare/Statement.lean
check_decl "target sphere locally path-connected theorem is declared" \
  '^theorem threeSphere_locPathConnectedSpace\b' Poincare/Statement.lean
check_decl "target sphere locally path-connected equality contract is declared" \
  '^theorem threeSphere_locPathConnectedSpace_eq\b' Poincare/Statement.lean
check_decl "target sphere connected type theorem is declared" \
  '^theorem threeSphere_connectedSpace\b' Poincare/Statement.lean
check_decl "target sphere connected type equality contract is declared" \
  '^theorem threeSphere_connectedSpace_eq\b' Poincare/Statement.lean
check_decl "target sphere nonempty theorem is declared" \
  '^theorem threeSphere_nonempty\b' Poincare/Statement.lean
check_decl "target sphere nonempty equality contract is declared" \
  '^theorem threeSphere_nonempty_eq\b' Poincare/Statement.lean
check_decl "target sphere prerequisite payload theorem is declared" \
  '^theorem threeSphere_target_prerequisites_except_simpleConnected\b' Poincare/Statement.lean
check_decl "target sphere prerequisite payload equality contract is declared" \
  '^theorem threeSphere_target_prerequisites_except_simpleConnected_eq\b' Poincare/Statement.lean
check_decl "target sphere full prerequisite payload theorem is declared" \
